command.text:

var f = this, hidden = '*******' + String.fromCharCode(255), l = (f._language == 'v' ? 0 : 1), message = [
  ['Mật khẩu vừa nhập không hợp lệ.', 'Your password is too simple. Please retype.'],
  ['Kiểm tra lại mật khẩu nhập không đúng.', 'Your password is invalid. Please retype.'],
  ['Mật khẩu tối thiểu phải từ &l; ký tự.', 'Password must consist of at least &l; characters.'],
  ['Mật khẩu tối thiểu phải từ &l; ký tự và phải có số và chữ', 'Password must consist of at least &l; characters in both numbers and letters.'],
  ['Mật khẩu tối thiểu phải từ &l; ký tự và phải có số, chữ, chữ hoa.', 'Password must consist of at least &l; characters in both numbers and letters with upper-case letter.'],
  ['Mật khẩu tối thiểu phải từ &l; ký tự và phải có số, chữ, chữ hoa, kí tự khác ngoài chữ và số.', 'Password must consist of at least &l; characters in both numbers and letters with upper-case letter and other characters except numbers and letters.']
],
o1 = f.getItem('cpass'), o2 = f.getItem('view_pass'), o3 = f.getItem('view_pass2'),
k = $func.trim(o1.value), p = $func.trim(o2.value), u = $func.trim(o3.value), v = (p != hidden), errorMessage = null,
username = $func.trim(f.getItemValue('name')), pwd = AES(MD5(k), f._key, MD5(p));
/* <flatten type="Javascript"> */
o1.oldValue = o1.value, o2.oldValue = o2.value, o3.oldValue = o3.value;
o1.value = '', o2.value = '', o3.value = '';

checkFieldEntry(f, 'name', true)
checkFieldEntry(f, 'comment', true)
checkFieldEntry(f, o1);
checkFieldEntry(f, o2);
checkFieldEntry(f, o3);

if (f._checked) checkCode(this, 'name');
if (f._checked && ($func.trim(username).indexOf(' ', 0) >= 0 || username.indexOf('.', 0) >= 0)) {
  f._checked = false;
  var o = f.getItem('name');
  var msg = (f._language == 'v' ? 'Trường <span class="Highlight">{0}</span> không được phép có khoảng trắng hoặc chứa ký tự: <span class="Highlight">[.]</span>.' : 'Field <span class="Highlight">{0}</span> cannot contain blank or any of the following character: <span class="Highlight">[.]</span>.');
  msg = String.format(msg, o.field.Label);
  $message.show(msg, String.format('revertPassword(\'{0}\', \'\', true); $find(\'{0}\').focus(\'{1}\');', f._id, o.field.Name));
}
/* </flatten> */
if (f._checked) {
  if (v) {
    if ((f._wordList.indexOf(p) > -1) || (p == username)) errorMessage = message[0][l];
    if (p != u) errorMessage = message[1][l];
    else {
      var type = f.getItemValue('pwd_type');
      switch (type) {
        case 2:
          if (p.length < &l;) errorMessage = message[2][l];
          break;
        case 3:
          if (!/^(?=.*\d)(?=.*[a-z]).{&l;,}/.test(p)) errorMessage = message[3][l];
          break;
        case 4:
          if (!/^(?=.*\d)(?=.*[a-z])(?=.*[A-Z]).{&l;,}/.test(p)) errorMessage = message[4][l];
          break;
        case 5:
          if (!/^(?=.*\d)(?=.*[a-z])(?=.*[A-Z])(?=.*[\W]).{&l;,}/.test(p)) errorMessage = message[5][l];
          break;
        default:
          break;
       }
    }
  }
  if (errorMessage) {
    f._checked = false;
    $func.hideWait(f.get_id());
    $message.show(errorMessage, String.format('revertPassword(\'{0}\', \'\', true); $find(\'{0}\').focus(\'{1}\');', f.get_id(), 'view_pass'));
  }
  else {
    if (v) {
      f.setItemValue('pass', pwd);
      f.setItemValue('pwd_update_yn', 1);
    } else f.setItemValue('pwd_update_yn', 0);
  }
  &ProfileScriptChecking;
}

