script.text:
      /* <flatten type="Javascript"> */
function initForm(f) {setFormInitValue(f);}
/* </flatten> */
function loadForm(f) {
  &ProfileFixCss;
  var g = f.grid;
  f.add_onResponseComplete(on$Form$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onTabChanged);
  f._tabContainer._loaded = true;
  changeLookupReadonly(f, 'restrict_users', true);
  if (f._trial) {
    f.getItem('dien_thoai').disabled = true;
    f.getItem('e_mail').disabled = true;
  }
  &ProfileScriptLoad;
  focusObject(f);
  if ((f._action == 'New') && f._$init && !g._activeCell) f.request('Key', 'Key', []);
  f._$init = true;
}
/* <flatten type="Javascript"> */
function scatterForm(f) {focusObject(f);}
function focusObject(f) {
  var o = f.getItem('name');
  o.disabled = false;
  o.focus();
  if (f._action == 'Edit' && f._isAdmin == 0) {
    if (f._userID == f.getItemValue('id')) {
      f.getItem('comment').focus();
      o.disabled = true;
    }
  }
}
/* </flatten> */
function closeForm(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Form$ResponseComplete);} catch (ex) {}
  &ProfileScriptClose;
}
/* <flatten type="Javascript"> */
function on$Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Key':
      f._key = result[0].Value;
      break;
    default:
      break;
  }
}
/* </flatten> */
function onTabChanged(sender, e) {sender.parentForm.focusWhenTabChanged(['view_pass',&ProfileTab; sender.parentForm._trial ? 'd_language' : 'dien_thoai']);}
/* <flatten type="Javascript"> */
function setFormInitValue(f) {
  if (f._isAdmin == 0) {
    var a = ['pwd_type', 'pwd_daychange', 'pwd_useold_yn', 'restrict_yn', 'restrict_users', 'status', 'alz_yn'&DeviceUserVisible;];
    if (f.getItemValue('id') == f._userID) a.push('pwd_nextlogin_yn');
    for (var i = 0; i < a.length; i++) {
      try {$common.setVisible(f.getItem(a[i]).parentNode.parentNode.parentNode, false);} catch (ex) {}
    }
  }
  if ((f.getItemValue('admin') == 1) && (f._isAdmin == 1)) {
    f.getItem('restrict_yn').checked = f.getItem('status').disabled = f.getItem('restrict_yn').disabled = f.getItem('restrict_users').disabled = true;
    f._setReadOnly(f.getItem('restrict_users'), true);
  }
}
function genHash(o) {var f = o.parentForm;
  var p = $func.trim(MD5(o.value)), k = $func.trim(f._key)
  var s = k.substr(0, 8) + p.substr(1, p.length - 2), crc = CRC32(s);
  if (o.field.Name == 'cpass') {f.getItem('chkpass').value = crc;}
  else {
    if ((f.getItem('view_pass').value == f.getItem('view_pass2').value) && (f._isAdmin == 0)) {f.getItem('chkdup').value = crc;}
    else {f.getItem('chkdup').value = 0;}
  }
}
function checkFieldEntry(f, o, force) {
  if (force) o = f.getItem(o);
  var v = force ? o.value : o.oldValue;
  if (f._checked && !v) {
    f._checked = false;
    $func.hideWait(f.get_id());
    $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), o.field.Label), String.format('revertPassword(\'{0}\', \'\', true); $find(\'{0}\').focus(\'{1}\');', f.get_id(), o.field.Name));
  }
}
function revertPassword(f, name, force) {
  if (force) f = $find(f);
  var o1 = f.getItem('cpass'), o2 = f.getItem('view_pass'), o3 = f.getItem('view_pass2');
  if (o1.oldValue) o1.value = o1.oldValue;
  if (o2.oldValue) o2.value = o2.oldValue;
  if (o3.oldValue) o3.value = o3.oldValue;
  if (name) f.focus(name);
}
function checkCode(f, field) {
  var a = field.split(','), s = '\'`~!@#$%^&*(),;"<>?/\\,_', d = $func.htmlEncode(s);
  for (var i = 0; i < a.length; i++) {
    var e = null, name = $func.trim(a[i]), o = f.getItem(name), c = o.value, l = o.field.Label;
    if (c.length > 0) {
      if (c[0] == ' ') e = true;
      else {
        for (var j = 0; j < c.length; j++) {
          if (s.indexOf(c[j]) >= 0) {
            e = true;
            break;
          }
        }
      }
    }
    if (e) {
      var msg = (f._language == 'v' ? 'Trường <span class="Highlight">{0}</span> không được phép có khoảng trắng ở đầu hoặc chứa các ký tự: <span class="Highlight">{1}</span>.' : 'Field <span class="Highlight">{0}</span> cannot contain blank at the beginning or any of the following characters: <span class="Highlight">{1}</span>.');
      msg = String.format(msg, l, d);
      f._checked = false;
      $func.hideWait(f.get_id());
      $message.show(msg, String.format('revertPassword(\'{0}\', \'\', true); $find(\'{0}\').getItem(\'' + name + '\').focus();', f.get_id()));
      return false;
    }
  }
  return true;
}

function setObjectFormHidden(f, c) {
  var o = f.getItem(c), field = $func.findField(c, f._fields);
  $common.setVisible(o.parentNode.parentNode.parentNode, false);
  field.Hidden = true;
}
/* </flatten> */
